import type { UmbControllerHost } from "@umbraco-cms/backoffice/controller-api";
import { UmbLocalizationController } from '@umbraco-cms/backoffice/localization-api';
import { DateOptions, DateTimeOptions } from "@umbraco-forms/entities";
import { FieldData } from "@umbraco-forms/generated";
import { FieldPrevalueDetail } from "../types";

export class EntryRenderHelper {
  #host: UmbControllerHost;
  #localize: UmbLocalizationController;
  #fieldPrevalues: Array<FieldPrevalueDetail> = [];

  constructor(host: UmbControllerHost, fieldPrevalues: Array<FieldPrevalueDetail>) {
    this.#host = host;
    this.#localize = new UmbLocalizationController(this.#host);
    this.#fieldPrevalues = fieldPrevalues;
  }

  getRenderValue(field: FieldData, view: string) {
    switch (view) {
      case "date":
        return this.#getDateValue(field, DateOptions);
      case "datetime":
        return this.#getDateValue(field, DateTimeOptions);
      case "number":
        return field.value;
      case "file":
        return this.#getFileValue(field);
      default:
        return this.#getTextValue(field);
    }
  }

  #getDateValue(field: FieldData, options: Intl.DateTimeFormatOptions) {
    try {
      return field.value && field.value.toString().length > 0 ? this.#localize.date(field.value.toString(), DateOptions) : "";
    } catch (error) {
      return field.value;
    }
  }

  #getFileValue(field: FieldData) {
    if (!field.value) {
      return "";
    }

    const fileNames = field.value.toString().split(", ").map(f => f.replace(/^.*[\\/]/, ''));
    return fileNames.join(", ");
  }

  #getTextValue(field: FieldData) {
    // If we have prevalues with captions, display those instead of the stored value.
    if (!field.value || field.value.toString().length === 0) {
      return "";
    }

    const prevalues = this.#getPrevaluesForField(field.fieldId);
    if (prevalues.length === 0) {
      return field.value.toString();
    }

    // If we find an exact match, use the caption where available.
    const matchedPrevalue = prevalues.find((x) => x.value === field.value);
    if (matchedPrevalue) {
      return matchedPrevalue.caption && matchedPrevalue.caption.length > 0 ? matchedPrevalue.caption : field.value;
    }

    // Also check the parts of the value separated by commas, as we could have a multiple value field.
    const fieldValueParts = Array.isArray(field.value) ? field.value : field.value.toString().split(", ");
    let replacedValue = "";
    for (let i = 0; i < fieldValueParts.length; i++) {
      if (i > 0) {
        replacedValue += ", ";
      }

      const fieldValuePart = fieldValueParts[i].trim();
      const matchedPrevalue = prevalues.find((x) => x.value === fieldValuePart);
      if (matchedPrevalue?.caption && matchedPrevalue.caption.length > 0) {
        replacedValue += matchedPrevalue.caption;
      }
      else {
        replacedValue += fieldValuePart;
      }
    }

    return replacedValue;
  }

  #getPrevaluesForField(fieldId: string) {
    const matchedFieldPrevalueData = this.#fieldPrevalues.find((f) => f.id === fieldId);
    if (matchedFieldPrevalueData) {
      return matchedFieldPrevalueData.prevalues;
    }

    return [];
  }
}
